function createQueuedBridge(getApi) {
  const queue = [];
  return {
    runOrQueue(action) {
      const api = getApi();
      if (api) {
        action(api);
        return;
      }
      queue.push(action);
    },
    flush() {
      const api = getApi();
      if (!api) return;
      while (queue.length > 0) {
        const action = queue.shift();
        action?.(api);
      }
    }
  };
}

